"""Severity policy definitions for vulnerability management.

Defines severity levels and thresholds used by the CI/CD gate
to determine pass/fail status for container image scans.
"""

from enum import IntEnum
from typing import List


class Severity(IntEnum):
    """Vulnerability severity levels aligned with Trivy/NVD scoring."""
    UNKNOWN = 0
    LOW = 1
    MEDIUM = 2
    HIGH = 3
    CRITICAL = 4

    @classmethod
    def from_string(cls, severity_str: str) -> 'Severity':
        """Parse a severity string (case-insensitive) to enum value."""
        try:
            return cls[severity_str.upper()]
        except KeyError:
            return cls.UNKNOWN


class SeverityThreshold:
    """Defines which severity levels should block deployment."""

    def __init__(self, block_on: List[Severity] = None):
        self.block_on = block_on or [Severity.CRITICAL, Severity.HIGH]

    def should_block(self, severity: Severity) -> bool:
        """Return True if the given severity should block deployment."""
        return severity in self.block_on

    def filter_blocking(self, vulnerabilities: list) -> list:
        """Return only vulnerabilities that meet the blocking threshold."""
        return [
            v for v in vulnerabilities
            if self.should_block(Severity.from_string(v.get('Severity', 'UNKNOWN')))
        ]

"""Tests for the image scanner module."""
import pytest
from unittest.mock import MagicMock, patch
from scanner.image_scanner import ImageScanner
from scanner.trivy_client import TrivyClient


# --- Mock Trivy responses ---

MOCK_CLEAN_SCAN = {"Results": [{"Vulnerabilities": []}]}

MOCK_CRITICAL_SCAN = {
    "Results": [{
        "Vulnerabilities": [
            {"VulnerabilityID": "CVE-2024-1001", "Severity": "CRITICAL", "PkgName": "openssl",
             "InstalledVersion": "1.1.1k", "FixedVersion": "1.1.1l", "Description": "Buffer overflow in OpenSSL"}
        ]
    }]
}

MOCK_HIGH_SCAN = {
    "Results": [{
        "Vulnerabilities": [
            {"VulnerabilityID": "CVE-2024-2002", "Severity": "HIGH", "PkgName": "curl",
             "InstalledVersion": "7.74.0", "FixedVersion": "7.79.0", "Description": "HSTS bypass in curl"}
        ]
    }]
}

MOCK_MEDIUM_SCAN = {
    "Results": [{
        "Vulnerabilities": [
            {"VulnerabilityID": "CVE-2024-3003", "Severity": "MEDIUM", "PkgName": "zlib",
             "InstalledVersion": "1.2.11", "FixedVersion": "1.2.12", "Description": "Memory corruption in zlib"}
        ]
    }]
}

MOCK_MIXED_SCAN = {
    "Results": [{
        "Vulnerabilities": [
            {"VulnerabilityID": "CVE-2024-1001", "Severity": "CRITICAL", "PkgName": "openssl",
             "InstalledVersion": "1.1.1k", "FixedVersion": "1.1.1l", "Description": "Buffer overflow"},
            {"VulnerabilityID": "CVE-2024-3003", "Severity": "MEDIUM", "PkgName": "zlib",
             "InstalledVersion": "1.2.11", "FixedVersion": "1.2.12", "Description": "Memory corruption"},
            {"VulnerabilityID": "CVE-2024-4004", "Severity": "LOW", "PkgName": "bash",
             "InstalledVersion": "5.1.4", "FixedVersion": "5.1.8", "Description": "Minor issue"}
        ]
    }]
}


def _make_scanner(mock_response):
    mock_client = MagicMock(spec=TrivyClient)
    mock_client.scan_image.return_value = mock_response
    scanner = ImageScanner(trivy_client=mock_client)
    return scanner


def test_parse_trivy_results():
    scanner = _make_scanner(MOCK_MIXED_SCAN)
    vulns = scanner._parse_trivy_results(MOCK_MIXED_SCAN)
    assert len(vulns) == 3
    assert vulns[0]['id'] == 'CVE-2024-1001'
    assert vulns[0]['severity'] == 'CRITICAL'


def test_parse_empty_results():
    scanner = _make_scanner(MOCK_CLEAN_SCAN)
    vulns = scanner._parse_trivy_results({"Results": []})
    assert len(vulns) == 0


def test_scan_and_validate_clean_image():
    scanner = _make_scanner(MOCK_CLEAN_SCAN)
    result = scanner.scan_and_validate('docker.io/library/alpine:3.18')
    assert result['gate_decision']['passed'] is True


def test_scan_and_validate_critical_vuln_blocks():
    scanner = _make_scanner(MOCK_CRITICAL_SCAN)
    result = scanner.scan_and_validate('docker.io/library/nginx:1.21')
    assert result['gate_decision']['passed'] is False
    assert result['gate_decision']['blocking_vulnerabilities'] >= 1


def test_scan_and_validate_high_vuln_blocks():
    scanner = _make_scanner(MOCK_HIGH_SCAN)
    result = scanner.scan_and_validate('docker.io/library/python:3.9')
    assert result['gate_decision']['passed'] is False


def test_scan_and_validate_medium_vuln_passes():
    scanner = _make_scanner(MOCK_MEDIUM_SCAN)
    result = scanner.scan_and_validate('docker.io/library/node:16')
    assert result['gate_decision']['passed'] is True


def test_report_generation():
    scanner = _make_scanner(MOCK_MIXED_SCAN)
    result = scanner.scan_and_validate('docker.io/library/ubuntu:22.04')
    report = result['report']
    assert 'severity_summary' in report
    assert report['total_findings'] == 3
    assert report['compliance_framework'] == 'SOC2-Type-II'
